-- ENGINEER_WRITTEN 2024년 제3회 기출 복원 — 100문항 일괄 적재
-- mock_exam: kind=PAST_EXAM, visibility=PUBLISHED, expert_verified=0
--
-- 재실행 안전성 — 동일 조합(exam_type + PAST_EXAM + 연도/회차) 정리 후 재삽입
DELETE FROM mock_exam
  WHERE exam_type = 'ENGINEER_WRITTEN'
    AND kind = 'PAST_EXAM'
    AND exam_year = 2024
    AND exam_round = 3;

SET @seq := (SELECT COALESCE(MAX(sequence), 0) + 1 FROM mock_exam WHERE exam_type = 'ENGINEER_WRITTEN');

INSERT INTO mock_exam
  (name, exam_type, sequence, visibility, expert_verified,
   kind, exam_year, exam_round, exam_date, created_at, updated_at)
VALUES
  ('정보처리기사 필기 2024년 3회 복원', 'ENGINEER_WRITTEN', @seq, 'PUBLISHED', 0,
   'PAST_EXAM', 2024, 3, '2024-07-05', NOW(6), NOW(6));

SET @mock_exam_id := LAST_INSERT_ID();

INSERT INTO question
  (subject_id, content, question_type, correct_option, explanation,
   topic, difficulty, mock_exam_id, display_order,
   verification_category, content_hash, created_at, updated_at)
VALUES
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 현행 시스템 분석 시 고려해야 할 사항과 거리가 먼 것은 무엇인가?\n\n① 시스템 구성\n② 소프트웨어 구성\n③ 개발자 구성\n④ 하드웨어 구성', 'MCQ', 3, '정답: 3. 현행 시스템 분석은 시스템 구성, 소프트웨어 구성, 하드웨어 구성을 파악하는 활동이며 개발자 구성은 핵심 분석 항목이 아니다.\n\n**오답 풀이**\n- 1번: 시스템 구성은 현행 시스템 분석 대상이다.\n- 2번: 소프트웨어 구성은 현행 시스템 분석 대상이다.\n- 3번: 개발자 구성은 현행 시스템 분석의 주요 고려사항과 거리가 멀다.\n- 4번: 하드웨어 구성은 현행 시스템 분석 대상이다.\n\n**보충 개념**\n현행 시스템 분석은 현재 운영 중인 시스템의 구성, 기능, 인터페이스, 데이터, 인프라 등을 파악하는 과정이다.',
   '현행 시스템 분석', 1, @mock_exam_id, 1, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 럼바우 분석 프로세스에서 사용되는 다이어그램이 아닌 것은 무엇인가?\n\n① 객체 다이어그램\n② 자료 흐름도\n③ 소멸 차트\n④ 활동 다이어그램', 'MCQ', 3, '정답: 3. 럼바우 분석은 객체 모델링, 동적 모델링, 기능 모델링으로 구성되며 소멸 차트는 해당하지 않는다.\n\n**오답 풀이**\n- 1번: 객체 다이어그램은 객체 모델링에 사용된다.\n- 2번: 자료 흐름도는 기능 모델링에 사용된다.\n- 3번: 소멸 차트는 럼바우 분석 프로세스의 다이어그램이 아니다.\n- 4번: 활동 다이어그램은 동적 모델링과 관련된다.\n\n**보충 개념**\n럼바우 분석 기법은 객체 모델링, 동적 모델링, 기능 모델링의 세 관점으로 시스템을 분석한다.',
   '럼바우 분석', 2, @mock_exam_id, 2, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 아래와 같은 형태의 오류는 무엇인가?\n\n**<보기>**\n`ks-002A → ks-00A2`\n\n① Omission\n② Transcription\n③ Addition\n④ Transposition', 'MCQ', 4, '정답: 4. 문자의 위치가 서로 바뀐 오류이므로 전위 오류(Transposition)에 해당한다.\n\n**오답 풀이**\n- 1번: Omission은 문자를 빠뜨리는 생략 오류이다.\n- 2번: Transcription은 한 문자를 잘못 기록하는 필사 오류이다.\n- 3번: Addition은 불필요한 문자가 추가되는 오류이다.\n- 4번: Transposition은 문자의 위치가 바뀌는 오류이다.\n\n**보충 개념**\n코드 오류 유형은 생략, 필사, 추가, 전위 오류 등으로 구분된다.',
   '코드 오류', 2, @mock_exam_id, 3, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 나선형 모델의 개발 프로세스가 아닌 것은 무엇인가?\n\n① 고객 평가\n② 유지보수\n③ 위험 분석\n④ 공학적 개발 및 검증', 'MCQ', 2, '정답: 2. 나선형 모델의 주요 반복 절차는 계획 및 목표 설정, 위험 분석, 공학적 개발 및 검증, 고객 평가이다.\n\n**오답 풀이**\n- 1번: 고객 평가는 나선형 모델의 절차이다.\n- 2번: 유지보수는 나선형 모델의 대표 개발 프로세스 단계가 아니다.\n- 3번: 위험 분석은 나선형 모델의 핵심 단계이다.\n- 4번: 공학적 개발 및 검증은 나선형 모델의 절차이다.\n\n**보충 개념**\n나선형 모델은 반복적으로 위험을 분석하고 점진적으로 시스템을 완성하는 개발 모델이다.',
   '나선형 모델', 1, @mock_exam_id, 4, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 UML에 대한 설명과 가장 거리가 먼 것은 무엇인가?\n\n① 구조, 행동, 그룹 등의 사물이 존재한다.\n② 생성, 구조, 행위 다이어그램이 있다.\n③ 사물, 관계, 다이어그램으로 구성된다.\n④ 관계는 사물과 사물의 연관성을 표현한 것이다.', 'MCQ', 2, '정답: 2. 생성, 구조, 행위는 디자인 패턴의 분류이며 UML 다이어그램 분류와 다르다.\n\n**오답 풀이**\n- 1번: UML에는 구조, 행동, 그룹 등의 사물이 있다.\n- 2번: 생성, 구조, 행위는 GoF 디자인 패턴의 분류이다.\n- 3번: UML은 사물, 관계, 다이어그램으로 구성된다.\n- 4번: 관계는 사물 사이의 연관성을 표현한다.\n\n**보충 개념**\nUML은 소프트웨어 시스템을 시각적으로 모델링하기 위한 표준 언어이다.',
   'UML', 2, @mock_exam_id, 5, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 XP의 가치에 해당하지 않는 것은 무엇인가?\n\n① 의사소통\n② 확약\n③ 피드백\n④ 존중', 'MCQ', 2, '정답: 2. XP의 핵심 가치는 의사소통, 단순성, 피드백, 용기, 존중이다.\n\n**오답 풀이**\n- 1번: 의사소통은 XP의 핵심 가치이다.\n- 2번: 확약은 XP의 대표 핵심 가치가 아니다.\n- 3번: 피드백은 XP의 핵심 가치이다.\n- 4번: 존중은 XP의 핵심 가치이다.\n\n**보충 개념**\nXP는 짧은 반복, 고객 참여, 테스트 중심 개발을 강조하는 애자일 방법론이다.',
   'XP', 1, @mock_exam_id, 6, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 정형기술검토(FTR)의 원칙이 아닌 것은 무엇인가?\n\n① 제품의 검토에만 집중한다.\n② 논쟁과 반박을 제한한다.\n③ 해결책이나 개선책에 대해 논의하지 않는다.\n④ 참가자의 수를 확대한다.', 'MCQ', 4, '정답: 4. FTR은 효율적인 검토를 위해 참가자 수를 제한하는 것이 원칙이다.\n\n**오답 풀이**\n- 1번: 제품 검토에 집중하는 것은 FTR 원칙이다.\n- 2번: 논쟁과 반박을 제한하는 것은 FTR 원칙이다.\n- 3번: 해결책보다 결함 발견에 집중하는 것이 FTR 원칙이다.\n- 4번: 참가자 수를 확대하는 것은 FTR 원칙이 아니다.\n\n**보충 개념**\nFTR은 산출물의 오류를 조기에 발견하기 위한 공식 기술 검토 활동이다.',
   'FTR', 1, @mock_exam_id, 7, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 행위 다이어그램의 종류에 해당하지 않는 것은 무엇인가?\n\n① 활동\n② 유스케이스\n③ 절차\n④ 클래스', 'MCQ', 4, '정답: 4. 클래스 다이어그램은 UML의 구조적 다이어그램에 해당한다.\n\n**오답 풀이**\n- 1번: 활동 다이어그램은 행위 다이어그램이다.\n- 2번: 유스케이스 다이어그램은 행위 다이어그램이다.\n- 3번: 절차 관련 다이어그램은 행위 표현과 관련된다.\n- 4번: 클래스 다이어그램은 정적 구조를 표현한다.\n\n**보충 개념**\nUML 다이어그램은 크게 구조 다이어그램과 행위 다이어그램으로 구분된다.',
   'UML 다이어그램', 1, @mock_exam_id, 8, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 성별 정보(남, 여)를 표현하기 위한 UI 요소로 가장 부적합한 것은 무엇인가?\n\n① Radio Button\n② Command Button\n③ Combo Box\n④ Check Box', 'MCQ', 2, '정답: 2. Command Button은 명령 실행용 UI 요소이므로 성별 선택 요소로 부적합하다.\n\n**오답 풀이**\n- 1번: Radio Button은 여러 항목 중 하나를 선택할 때 적합하다.\n- 2번: Command Button은 전송, 이동 같은 명령 수행에 사용된다.\n- 3번: Combo Box는 목록에서 하나의 값을 선택할 수 있다.\n- 4번: Check Box도 선택 UI이지만 단일 성별 선택에는 Radio Button이 더 적합하다.\n\n**보충 개념**\n성별처럼 하나의 값만 선택하는 항목에는 일반적으로 라디오 버튼이나 콤보 박스를 사용한다.',
   'UI 요소', 1, @mock_exam_id, 9, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 애자일 개발 프로세스의 가치가 아닌 것은 무엇인가?\n\n① 계획\n② 소통\n③ 협업\n④ 변화 대응', 'MCQ', 1, '정답: 1. 애자일은 계획 자체보다 소통, 협업, 변화 대응을 더 중시한다.\n\n**오답 풀이**\n- 1번: 계획은 애자일에서 상대적으로 덜 중시되는 가치이다.\n- 2번: 소통은 애자일의 핵심 가치이다.\n- 3번: 협업은 애자일의 핵심 가치이다.\n- 4번: 변화 대응은 애자일의 핵심 가치이다.\n\n**보충 개념**\n애자일은 변화에 빠르게 대응하고 고객과 협업하며 동작하는 소프트웨어를 지속적으로 제공하는 것을 중시한다.',
   '애자일', 1, @mock_exam_id, 10, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 자료 흐름도에 대한 설명과 거리가 먼 것은 무엇인가?\n\n① 데이터 출력을 위해서는 반드시 입력이 필요하다.\n② 기능에 의한 작업 소요시간을 파악하기 위한 도표이다.\n③ 프로세스, 자료 흐름, 자료 저장소, 단말로 구성된다.\n④ 최하위 프로세스는 소단위 명세서를 가진다.', 'MCQ', 2, '정답: 2. 자료 흐름도는 데이터 흐름을 표현하는 도구이며 작업 소요시간을 파악하는 도표가 아니다.\n\n**오답 풀이**\n- 1번: 출력 데이터에는 원인이 되는 입력이 필요하다.\n- 2번: 작업 소요시간 파악은 DFD의 목적이 아니다.\n- 3번: DFD는 프로세스, 자료 흐름, 자료 저장소, 단말로 구성된다.\n- 4번: 최하위 프로세스는 소단위 명세서로 구체화할 수 있다.\n\n**보충 개념**\nDFD는 시스템의 데이터 흐름과 처리 과정을 도식화하는 분석 도구이다.',
   'DFD', 2, @mock_exam_id, 11, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '기능과 데이터의 관계를 계층 구조로 표현하여 한눈에 이해하기 쉽도록 구성한 도표는 무엇인가?\n\n① Data Dictionary\n② Nassi-Schneiderman\n③ Hierarchy Input Process Output\n④ Data Flow Diagram', 'MCQ', 3, '정답: 3. HIPO는 기능과 데이터의 관계를 계층 구조로 표현하는 도표이다.\n\n**오답 풀이**\n- 1번: Data Dictionary는 자료 사전이다.\n- 2번: Nassi-Schneiderman은 논리 흐름을 구조적으로 표현하는 차트이다.\n- 3번: HIPO는 기능과 입출력 관계를 계층적으로 표현한다.\n- 4번: DFD는 데이터 흐름을 표현한다.\n\n**보충 개념**\nHIPO는 시스템 기능을 하향식으로 분석하고 문서화하는 데 사용된다.',
   'HIPO', 1, @mock_exam_id, 12, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '시스템 카탈로그에 대한 설명과 거리가 먼 것은 무엇인가?\n\n① DBMS가 스스로 생성하고 유지한다.\n② 데이터베이스 객체가 변경되면 자동으로 변경된다.\n③ DCL을 통해 내용 조회가 가능하다.\n④ 직접적인 변경은 불가능하다.', 'MCQ', 3, '정답: 3. 시스템 카탈로그는 DML을 통해 조회할 수 있으며 DCL로 조회하는 것이 아니다.\n\n**오답 풀이**\n- 1번: 시스템 카탈로그는 DBMS가 생성하고 유지한다.\n- 2번: 객체 변경 시 DBMS가 카탈로그를 갱신한다.\n- 3번: 조회는 DML로 수행한다.\n- 4번: 사용자가 직접 변경할 수 없다.\n\n**보충 개념**\n시스템 카탈로그는 테이블, 뷰, 인덱스, 권한 등 데이터베이스 객체 정보를 저장한다.',
   '시스템 카탈로그', 2, @mock_exam_id, 13, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'SW공학의 기본 원칙에 해당하지 않는 것은 무엇인가?\n\n① 현대적인 프로그래밍 기술을 지속적으로 적용한다.\n② 소프트웨어에 대한 하드웨어의 상대적 비용을 절감한다.\n③ 개발 단계별 산출물에 대한 명확한 기록을 유지한다.\n④ 품질에 대한 지속적인 검증이 필요하다.', 'MCQ', 2, '정답: 2. 소프트웨어 공학은 하드웨어에 대한 소프트웨어의 상대적 비용 절감을 목적으로 설명된다.\n\n**오답 풀이**\n- 1번: 현대적 프로그래밍 기술 적용은 기본 원칙이다.\n- 2번: 표현이 반대로 되어 있어 기본 원칙과 맞지 않는다.\n- 3번: 산출물 기록 유지는 기본 원칙이다.\n- 4번: 품질 검증은 기본 원칙이다.\n\n**보충 개념**\n소프트웨어 공학은 개발 비용과 기간 예측, 품질 향상, 유지보수성 향상을 목표로 한다.',
   '소프트웨어 공학', 2, @mock_exam_id, 14, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'NUI에서 사용하는 터치 제스처에 해당하지 않는 것은 무엇인가?\n\n① Tap\n② Pinch\n③ Drag\n④ Click', 'MCQ', 4, '정답: 4. Click은 마우스 기반 입력 동작에 가깝고 대표적인 터치 제스처가 아니다.\n\n**오답 풀이**\n- 1번: Tap은 터치 제스처이다.\n- 2번: Pinch는 확대·축소에 사용되는 터치 제스처이다.\n- 3번: Drag는 터치 제스처이다.\n- 4번: Click은 마우스 조작에 해당한다.\n\n**보충 개념**\nNUI 터치 제스처에는 Tap, Double Tap, Drag, Flick, Pinch, Press, Rotate, Swipe 등이 있다.',
   'NUI', 1, @mock_exam_id, 15, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중 올바른 설계 방향에 대한 내용은 무엇인가?\n\n① 공유도와 응집도는 높이고, 제어도와 결합도는 낮추도록 설계되어야 한다.\n② 공유도와 제어도는 높이고, 결합도와 응집도는 낮추도록 설계되어야 한다.\n③ 공유도와 제어도는 낮추고, 결합도와 응집도는 낮추도록 설계되어야 한다.\n④ 공유도와 응집도는 낮추고, 제어도와 결합도는 높이도록 설계되어야 한다.', 'MCQ', 1, '정답: 1. 좋은 설계는 공유도와 응집도를 높이고 제어도와 결합도를 낮추는 방향을 지향한다.\n\n**오답 풀이**\n- 1번: 올바른 설계 방향이다.\n- 2번: 응집도를 낮추는 것은 바람직하지 않다.\n- 3번: 응집도를 낮추는 것은 바람직하지 않다.\n- 4번: 결합도를 높이는 것은 바람직하지 않다.\n\n**보충 개념**\n모듈 설계에서는 응집도는 높고 결합도는 낮을수록 유지보수성이 좋아진다.',
   '설계 품질', 2, @mock_exam_id, 16, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '소프트웨어의 전체적인 설계 단계를 상위/하위로 나눌 때, 상위 설계에 해당하지 않는 항목은 무엇인가?\n\n① 내부 로직\n② 시스템 구조\n③ 화면 구성\n④ DB 설계', 'MCQ', 1, '정답: 1. 내부 로직은 하위 설계 또는 상세 설계에 해당한다.\n\n**오답 풀이**\n- 1번: 내부 로직은 모듈 내부 상세 설계에 해당한다.\n- 2번: 시스템 구조는 상위 설계에 해당한다.\n- 3번: 화면 구성은 상위 설계에 해당한다.\n- 4번: DB 설계는 상위 설계에 포함될 수 있다.\n\n**보충 개념**\n상위 설계는 아키텍처, 화면, DB 등 전체 구조를 다루고 하위 설계는 모듈 내부 로직을 다룬다.',
   '상위 설계', 1, @mock_exam_id, 17, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '요구사항 모델링에서 일반적으로 사용되는 다이어그램은 무엇인가?\n\n① Overview\n② Data Dictionary\n③ UML\n④ Visual Table', 'MCQ', 3, '정답: 3. UML은 요구사항 모델링과 시스템 분석·설계에 사용되는 표준 모델링 언어이다.\n\n**오답 풀이**\n- 1번: Overview는 대표 모델링 다이어그램 명칭으로 보기 어렵다.\n- 2번: Data Dictionary는 자료 사전이다.\n- 3번: UML은 요구사항 모델링에 일반적으로 사용된다.\n- 4번: Visual Table은 대표 모델링 다이어그램이 아니다.\n\n**보충 개념**\nUML은 개발자와 고객 간 의사소통을 돕기 위해 시스템을 시각적으로 표현한다.',
   '요구사항 모델링', 1, @mock_exam_id, 18, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '서브 시스템에 입력된 데이터를 처리한 결과를 다음 서브 시스템으로 전달하는 형식의 아키텍처는 무엇인가?\n\n① Pipe-Filter\n② Peer-To-Peer\n③ Broker\n④ MVC', 'MCQ', 1, '정답: 1. Pipe-Filter는 데이터를 필터에서 처리한 뒤 파이프를 통해 다음 단계로 전달하는 구조이다.\n\n**오답 풀이**\n- 1번: Pipe-Filter는 순차적 데이터 처리에 적합하다.\n- 2번: Peer-To-Peer는 각 컴포넌트가 서버와 클라이언트 역할을 모두 수행할 수 있다.\n- 3번: Broker는 요청을 중개하는 구조이다.\n- 4번: MVC는 모델, 뷰, 컨트롤러를 분리하는 구조이다.\n\n**보충 개념**\nPipe-Filter 패턴은 컴파일러, 데이터 변환, 스트림 처리 등에 자주 사용된다.',
   '파이프-필터', 2, @mock_exam_id, 19, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '폭포수 모델에 대한 설명과 가장 거리가 먼 것은 무엇인가?\n\n① 정해진 단계를 한 번씩만 진행하며 이전 단계로 돌아갈 수 없다.\n② 결과물이 명확하게 산출되어야 다음 단계로 넘어가는 방식이다.\n③ 과거부터 현재까지 가장 폭넓게 사용되는 방식이다.\n④ 제품의 기능 보완이 불가능하므로 매뉴얼 작성이 필수적이다.', 'MCQ', 3, '정답: 3. 폭포수 모델은 과거에 폭넓게 사용되던 방식이며 현재까지 가장 폭넓게 사용된다는 표현은 부적절하다.\n\n**오답 풀이**\n- 1번: 폭포수 모델은 순차적으로 진행된다.\n- 2번: 단계별 산출물이 명확해야 다음 단계로 넘어간다.\n- 3번: 현재까지 가장 폭넓게 사용된다는 설명은 과장되어 있다.\n- 4번: 순차 진행 특성상 기능 보완이 어렵다는 설명은 관련된다.\n\n**보충 개념**\n폭포수 모델은 요구분석부터 유지보수까지 단계를 순차적으로 진행하는 전통적 개발 모델이다.',
   '폭포수 모델', 2, @mock_exam_id, 20, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '프로젝트를 진행하는 도중에 새로운 인원을 투입하는 경우 오히려 개발 일정을 지연시킬 수 있다. 이에 해당하는 법칙은 무엇인가?\n\n① Brooks의 법칙\n② Effort의 법칙\n③ Pareto의 법칙\n④ Context의 법칙', 'MCQ', 1, '정답: 1. 브룩스의 법칙은 지연된 프로젝트에 인력을 추가하면 일정이 더 지연될 수 있다는 법칙이다.\n\n**오답 풀이**\n- 1번: Brooks의 법칙이 해당한다.\n- 2번: Effort의 법칙은 문제의 설명과 다르다.\n- 3번: Pareto의 법칙은 80:20 법칙이다.\n- 4번: Context의 법칙은 문맥에 따라 의미가 달라지는 것과 관련된다.\n\n**보충 개념**\n새로운 인원 투입은 교육과 의사소통 비용을 증가시켜 프로젝트 지연을 악화할 수 있다.',
   '브룩스의 법칙', 1, @mock_exam_id, 21, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 최악의 시간 복잡도를 기준으로 나머지 셋과 다른 시간 복잡도를 가지는 정렬은 무엇인가?\n\n① 삽입 정렬\n② 버블 정렬\n③ 선택 정렬\n④ 힙 정렬', 'MCQ', 4, '정답: 4. 삽입, 버블, 선택 정렬의 최악 시간 복잡도는 O(n²)이고 힙 정렬은 O(n log n)이다.\n\n**오답 풀이**\n- 1번: 삽입 정렬의 최악 시간 복잡도는 O(n²)이다.\n- 2번: 버블 정렬의 최악 시간 복잡도는 O(n²)이다.\n- 3번: 선택 정렬의 최악 시간 복잡도는 O(n²)이다.\n- 4번: 힙 정렬은 최악 시간 복잡도가 O(n log n)이다.\n\n**보충 개념**\n정렬 알고리즘은 평균, 최악, 최선 시간 복잡도를 구분해서 이해해야 한다.',
   '정렬 시간 복잡도', 2, @mock_exam_id, 22, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 프로그램 개발 언어의 선정 기준과 가장 거리가 먼 것은 무엇인가?\n\n① 알고리즘 및 자료 구조의 난이도를 고려해야 한다.\n② 프로젝트 진행 인원의 스케줄을 고려해야 한다.\n③ 소프트웨어의 수행 환경을 고려해야 한다.\n④ 담당 개발자의 경험과 지식 등을 고려해야 한다.', 'MCQ', 2, '정답: 2. 프로젝트 진행 인원의 스케줄은 일정 계획 요소이며 개발 언어 선정 기준과는 거리가 멀다.\n\n**오답 풀이**\n- 1번: 알고리즘과 자료 구조 난이도는 언어 선정에 영향을 줄 수 있다.\n- 2번: 인원 스케줄은 언어 선정 기준으로 보기 어렵다.\n- 3번: 수행 환경은 언어 선정 기준이다.\n- 4번: 개발자의 경험과 지식도 언어 선정 기준이 될 수 있다.\n\n**보충 개념**\n개발 언어 선정 시 성능, 수행 환경, 개발자 역량, 라이브러리, 유지보수성 등을 고려한다.',
   '개발 언어 선정', 1, @mock_exam_id, 23, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '분기마다 가장 최적의 해를 선택하여 결과를 도출하는 방식의 알고리즘으로, 반드시 종합적인 최적의 해를 보장하지 않는 기법은 무엇인가?\n\n① Greedy\n② Dynamic\n③ Recursive\n④ Backtracking', 'MCQ', 1, '정답: 1. Greedy 알고리즘은 매 단계에서 가장 좋아 보이는 선택을 하지만 항상 전체 최적해를 보장하지는 않는다.\n\n**오답 풀이**\n- 1번: Greedy는 탐욕적 선택을 반복한다.\n- 2번: Dynamic은 부분 문제의 해를 저장해 활용한다.\n- 3번: Recursive는 자기 자신을 호출하는 방식이다.\n- 4번: Backtracking은 조건에 맞지 않으면 되돌아가 탐색한다.\n\n**보충 개념**\n탐욕 알고리즘은 특정 조건에서만 최적해를 보장한다.',
   '탐욕 알고리즘', 2, @mock_exam_id, 24, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 소스 코드의 정적 분석 도구에 해당하지 않는 것은 무엇인가?\n\n① cppcheck\n② SonarQube\n③ checkstyle\n④ Valgrind', 'MCQ', 4, '정답: 4. Valgrind는 프로그램 실행 중 메모리 오류 등을 분석하는 동적 분석 도구이다.\n\n**오답 풀이**\n- 1번: cppcheck는 정적 분석 도구이다.\n- 2번: SonarQube는 정적 분석 도구이다.\n- 3번: checkstyle은 코드 스타일 검사 도구이다.\n- 4번: Valgrind는 동적 분석 도구이다.\n\n**보충 개념**\n정적 분석은 실행하지 않고 소스 코드를 검사하고, 동적 분석은 실행 중 동작을 검사한다.',
   '정적 분석', 1, @mock_exam_id, 25, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 아래의 중위식을 후위식으로 올바르게 변환한 것은 무엇인가?\n\n**<보기>**\n`(A-B)*C+D`\n\n① AB-C+D*\n② A-BC*D+\n③ AB-C*D+\n④ A-B-CD*+', 'MCQ', 3, '정답: 3. 괄호 안의 A-B를 먼저 처리한 뒤 C와 곱하고 D를 더하면 후위식은 AB-C*D+가 된다.\n\n**오답 풀이**\n- 1번: 곱셈과 덧셈 연산자의 위치가 잘못되었다.\n- 2번: A와 B의 뺄셈 표현이 후위식 형식이 아니다.\n- 3번: 올바른 후위식이다.\n- 4번: 연산자와 피연산자 순서가 중위식 변환 결과와 다르다.\n\n**보충 개념**\n후위식은 연산자를 피연산자 뒤에 쓰며 괄호와 연산자 우선순위를 반영해야 한다.',
   '후위 표기식', 3, @mock_exam_id, 26, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '아주 오래된 소프트웨어는 그것을 개발한 개발자 또는 관련 참고문서 등이 없어서 유지보수가 어렵다. 해당 소프트웨어의 소스 코드를 의미하는 용어는 무엇인가?\n\n① Spaghetti Code\n② Alien Code\n③ Clean Code\n④ Hard Code', 'MCQ', 2, '정답: 2. Alien Code는 개발자나 관련 문서가 없어 유지보수가 어려운 코드를 의미한다.\n\n**오답 풀이**\n- 1번: Spaghetti Code는 코드 흐름이 복잡하게 얽힌 상태이다.\n- 2번: Alien Code는 이해하기 어려운 오래된 코드를 뜻한다.\n- 3번: Clean Code는 읽기 쉽고 유지보수하기 좋은 코드이다.\n- 4번: Hard Code는 값을 코드에 직접 고정하는 방식이다.\n\n**보충 개념**\n유지보수성이 낮은 코드는 문서화와 구조 개선을 통해 관리해야 한다.',
   'Alien Code', 1, @mock_exam_id, 27, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 소프트웨어 품질 목표에 해당하지 않는 것은 무엇인가?\n\n① 효율성\n② 준법성\n③ 이식성\n④ 유연성', 'MCQ', 2, '정답: 2. 준법성은 소프트웨어 품질 목표의 대표 항목으로 보기 어렵다.\n\n**오답 풀이**\n- 1번: 효율성은 품질 목표이다.\n- 2번: 준법성은 대표 품질 목표 항목이 아니다.\n- 3번: 이식성은 품질 목표이다.\n- 4번: 유연성은 품질 목표이다.\n\n**보충 개념**\n소프트웨어 품질 목표에는 정확성, 신뢰성, 효율성, 무결성, 유지보수성, 사용성, 이식성 등이 있다.',
   '소프트웨어 품질', 1, @mock_exam_id, 28, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 연결 리스트의 특징이 아닌 것은 무엇인가?\n\n① 배열의 단점을 보완한 자료구조이다.\n② 노드별 포인터를 활용하므로 배열보다 기억공간을 절약할 수 있다.\n③ 접근 속도는 배열보다 느린 편이다.\n④ 다양한 종류의 연결 리스트가 존재한다.', 'MCQ', 2, '정답: 2. 연결 리스트는 노드마다 포인터 공간이 필요하므로 배열보다 기억공간을 항상 절약한다고 보기 어렵다.\n\n**오답 풀이**\n- 1번: 연결 리스트는 삽입·삭제가 어려운 배열의 단점을 보완한다.\n- 2번: 포인터 저장 공간이 추가로 필요하다.\n- 3번: 임의 접근은 배열보다 느리다.\n- 4번: 단순, 이중, 원형 연결 리스트 등 다양한 종류가 있다.\n\n**보충 개념**\n연결 리스트는 삽입과 삭제가 유리하지만 인덱스 기반 접근은 배열보다 느리다.',
   '연결 리스트', 2, @mock_exam_id, 29, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 SPICE의 단계별 프로세스 수행 능력 단계가 잘못 짝지어진 것은 무엇인가?\n\n① 레벨0 - 불완전\n② 레벨1 - 수행\n③ 레벨2 - 최적\n④ 레벨3 - 확립', 'MCQ', 3, '정답: 3. SPICE의 레벨2는 관리 단계이며 최적 단계는 레벨5이다.\n\n**오답 풀이**\n- 1번: 레벨0은 불완전 단계이다.\n- 2번: 레벨1은 수행 단계이다.\n- 3번: 레벨2는 최적이 아니라 관리 단계이다.\n- 4번: 레벨3은 확립 단계이다.\n\n**보충 개념**\nSPICE 수행 능력 수준은 불완전, 수행, 관리, 확립, 예측 가능, 최적 단계로 구분된다.',
   'SPICE', 2, @mock_exam_id, 30, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 인스펙션 프로세스에서 빈칸에 해당하는 절차를 순서대로 나열한 것은 무엇인가?\n\n**<보기>**\n계획 → (ㄱ) → (ㄴ) → (ㄷ) → (ㄹ) → 후속 조치\n\n① 검토 회의, 수정, 사전 교육, 준비\n② 준비, 검토 회의, 수정, 사전 교육\n③ 사전 교육, 준비, 수정, 검토 회의\n④ 사전 교육, 준비, 검토 회의, 수정', 'MCQ', 4, '정답: 4. 인스펙션은 계획, 사전 교육, 준비, 검토 회의, 수정, 후속 조치 순으로 진행된다.\n\n**오답 풀이**\n- 1번: 검토 회의가 너무 앞에 배치되어 있다.\n- 2번: 사전 교육이 준비 이후로 배치되어 부적절하다.\n- 3번: 수정이 검토 회의보다 앞에 있어 부적절하다.\n- 4번: 올바른 순서이다.\n\n**보충 개념**\n인스펙션은 산출물을 체계적으로 검토하여 결함을 조기에 찾는 정적 테스트 활동이다.',
   '인스펙션', 2, @mock_exam_id, 31, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '문제 처리 프로세스를 도형을 통해 논리 중심으로 표현하는 구조적 분석 도구는 무엇인가?\n\n① DD\n② NS Chart\n③ DFD\n④ HIPO', 'MCQ', 2, '정답: 2. NS Chart는 순차, 선택, 반복 구조를 도형으로 표현하는 구조적 분석 도구이다.\n\n**오답 풀이**\n- 1번: DD는 자료 사전이다.\n- 2번: NS Chart는 논리 중심의 처리 흐름을 표현한다.\n- 3번: DFD는 데이터 흐름을 표현한다.\n- 4번: HIPO는 기능과 데이터 관계를 계층적으로 표현한다.\n\n**보충 개념**\nNS 차트는 구조적 프로그래밍의 제어 흐름을 명확히 표현하는 데 사용된다.',
   'NS 차트', 1, @mock_exam_id, 32, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '아래의 트리를 중위 순회(INORDER)하는 경우, 올바른 방문 순서는 무엇인가?\n\n**<그림>**\n<svg xmlns="http://www.w3.org/2000/svg" width="420" height="220" viewBox="0 0 420 220" role="img" aria-label="이진 트리"><style>.node{fill:#fff;stroke:#333;stroke-width:2}.edge{stroke:#333;stroke-width:2}.txt{font-size:16px;font-family:Arial,sans-serif;text-anchor:middle;dominant-baseline:middle}</style><line x1="210" y1="35" x2="140" y2="90" class="edge"/><line x1="210" y1="35" x2="280" y2="90" class="edge"/><line x1="140" y1="90" x2="90" y2="155" class="edge"/><line x1="280" y1="90" x2="235" y2="155" class="edge"/><line x1="280" y1="90" x2="330" y2="155" class="edge"/><circle cx="210" cy="35" r="22" class="node"/><text x="210" y="35" class="txt">A</text><circle cx="140" cy="90" r="22" class="node"/><text x="140" y="90" class="txt">B</text><circle cx="280" cy="90" r="22" class="node"/><text x="280" y="90" class="txt">C</text><circle cx="90" cy="155" r="22" class="node"/><text x="90" y="155" class="txt">D</text><circle cx="235" cy="155" r="22" class="node"/><text x="235" y="155" class="txt">E</text><circle cx="330" cy="155" r="22" class="node"/><text x="330" y="155" class="txt">F</text></svg>\n\n① B D A E C F\n② D B A E C F\n③ A B C D E F\n④ A B D C E F', 'MCQ', 2, '정답: 2. 중위 순회는 왼쪽 서브트리 → 루트 → 오른쪽 서브트리 순서이므로 D-B-A-E-C-F이다.\n\n**오답 풀이**\n- 1번: B와 D의 순서가 중위 순회와 다르다.\n- 2번: 올바른 중위 순회 결과이다.\n- 3번: 루트를 먼저 방문하므로 중위 순회가 아니다.\n- 4번: 오른쪽 서브트리 방문 순서가 맞지 않는다.\n\n**보충 개념**\n이진 트리 순회에는 전위, 중위, 후위 순회가 있으며 중위 순회는 Left-Root-Right 순서이다.',
   '트리 순회', 3, @mock_exam_id, 33, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 단위 테스트 도구에 해당하지 않는 것은?\n\n① AJAXUnit\n② CppUnit\n③ JUnit\n④ HttpUnit', 'MCQ', 1, '정답: 1. AJAXUnit은 대표적인 단위 테스트 도구로 분류되지 않는다.\n\n**오답 풀이**\n- 1번: AJAXUnit은 대표 단위 테스트 도구가 아니다.\n- 2번: CppUnit은 C++ 단위 테스트 도구이다.\n- 3번: JUnit은 Java 단위 테스트 도구이다.\n- 4번: HttpUnit은 웹 테스트 도구로 활용된다.\n\n**보충 개념**\nxUnit 계열 도구는 언어별 단위 테스트를 지원한다.',
   '단위 테스트 도구', 1, @mock_exam_id, 34, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '[42, 17, 85, 56, 23]의 수열을 삽입 정렬할 때, 1회전 후의 결과로 옳은 것은?\n\n① [17, 42, 85, 23, 56]\n② [17, 42, 23, 85, 56]\n③ [42, 17, 85, 56, 23]\n④ [17, 42, 85, 56, 23]', 'MCQ', 4, '정답: 4. 첫 번째 회전에서 17이 42 앞에 삽입되어 [17, 42, 85, 56, 23]이 된다.\n\n**오답 풀이**\n- 1번: 56과 23의 위치가 원문 수열과 다르다.\n- 2번: 23까지 이동한 결과가 아니므로 1회전 결과가 아니다.\n- 3번: 정렬이 전혀 진행되지 않은 원래 상태이다.\n- 4번: 1회전 후 결과와 일치한다.\n\n**보충 개념**\n삽입 정렬은 현재 원소를 앞쪽의 정렬된 영역에 알맞은 위치로 삽입한다.',
   '삽입 정렬', 2, @mock_exam_id, 35, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 소프트웨어 결함의 80%는 20%의 기능에 집중된다는 원리는 무엇인가?\n\n① 살충제 패러독스\n② 파레토의 법칙\n③ 오류-부재의 궤변\n④ 브룩스의 법칙', 'MCQ', 2, '정답: 2. 80%의 결과가 20%의 원인에서 발생한다는 원리는 파레토의 법칙이다.\n\n**오답 풀이**\n- 1번: 살충제 패러독스는 같은 테스트 반복 시 새 결함 발견이 어려워지는 현상이다.\n- 2번: 파레토의 법칙은 80:20 법칙이다.\n- 3번: 오류-부재의 궤변은 결함이 없어도 요구를 만족하지 못하면 품질이 낮다는 개념이다.\n- 4번: 브룩스의 법칙은 인력 추가와 일정 지연에 관한 법칙이다.\n\n**보충 개념**\n테스트에서는 결함이 많이 발생하는 핵심 영역을 집중적으로 관리해야 한다.',
   '파레토의 법칙', 1, @mock_exam_id, 36, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 블랙박스 테스트에 해당하는 것은 무엇인가?\n\n① Boundary Value Analysis\n② Basic Path\n③ Condition Testing\n④ Loop Testing', 'MCQ', 1, '정답: 1. Boundary Value Analysis는 입력값의 경계에서 결함을 찾는 블랙박스 테스트 기법이다.\n\n**오답 풀이**\n- 1번: 경계값 분석은 블랙박스 테스트이다.\n- 2번: Basic Path는 화이트박스 테스트이다.\n- 3번: Condition Testing은 화이트박스 테스트이다.\n- 4번: Loop Testing은 화이트박스 테스트이다.\n\n**보충 개념**\n블랙박스 테스트는 내부 구조를 보지 않고 입력과 출력 관점에서 테스트한다.',
   '블랙박스 테스트', 1, @mock_exam_id, 37, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 클린 코드의 작성 원칙에 해당하지 않는 것은 무엇인가?\n\n① 안정적이고 동일한 로직은 가급적 반복해서 작성한다.\n② 가독성이 높고 단순하며 의존성이 낮은 코드이다.\n③ 기능 및 설계에 대한 이해가 비교적 쉬운 코드이다.\n④ 기억하기 쉬운 용어 및 접두어를 사용하여 이름을 정의한다.', 'MCQ', 1, '정답: 1. 클린 코드는 중복을 최소화해야 하므로 동일 로직을 반복 작성하는 것은 원칙에 어긋난다.\n\n**오답 풀이**\n- 1번: 중복 작성은 클린 코드 원칙과 다르다.\n- 2번: 가독성, 단순성, 낮은 의존성은 클린 코드 원칙이다.\n- 3번: 이해하기 쉬운 코드는 클린 코드에 해당한다.\n- 4번: 명확한 이름 사용은 클린 코드 원칙이다.\n\n**보충 개념**\n클린 코드는 가독성, 단순성, 중복 최소화, 적절한 추상화를 중시한다.',
   'Clean Code', 1, @mock_exam_id, 38, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중 DRM 기술 요소에 해당하지 않는 것은?\n\n① 로그인\n② 인증\n③ 크랙 방지\n④ 키 관리', 'MCQ', 1, '정답: 1. 로그인은 일반적인 사용자 접근 절차이며 DRM 기술 요소로는 인증, 크랙 방지, 키 관리 등이 있다.\n\n**오답 풀이**\n- 1번: 로그인은 DRM 기술 요소로 보기 어렵다.\n- 2번: 인증은 DRM 기술 요소이다.\n- 3번: 크랙 방지는 DRM 기술 요소이다.\n- 4번: 키 관리는 DRM 기술 요소이다.\n\n**보충 개념**\nDRM은 디지털 콘텐츠의 사용 권한을 통제하기 위한 암호화, 키 관리, 인증, 정책 관리 등을 포함한다.',
   'DRM', 1, @mock_exam_id, 39, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), 'DRM 구성 요소 중, 디지털 콘텐츠 원본을 안전하게 유통하기 위한 전자적 보안 장치는 무엇인가?\n\n① 패키저\n② DRM 컨트롤러\n③ 보안 컨테이너\n④ 클리어링 하우스', 'MCQ', 3, '정답: 3. 보안 컨테이너는 디지털 콘텐츠 원본을 안전하게 유통하기 위한 전자적 보안 장치이다.\n\n**오답 풀이**\n- 1번: 패키저는 콘텐츠를 배포 가능한 형태로 묶고 암호화하는 프로그램이다.\n- 2번: DRM 컨트롤러는 콘텐츠 이용 권한을 통제한다.\n- 3번: 보안 컨테이너가 정답이다.\n- 4번: 클리어링 하우스는 라이선스 발급과 결제 관리를 수행한다.\n\n**보충 개념**\nDRM 구성 요소는 콘텐츠 보호, 권한 통제, 라이선스 관리 등으로 나뉜다.',
   'DRM 구성 요소', 2, @mock_exam_id, 40, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '어떤 릴레이션에서 각 속성이 아래와 같이 도메인을 가질 때, 이 릴레이션의 최대 기수는 얼마인가?\n\n| 속성 | 도메인 수 |\n|---|---:|\n| 성별 | 2 |\n| 학과 | 3 |\n| 수강형태 | 2 |\n\n① 3\n② 7\n③ 셀 수 없음\n④ 12', 'MCQ', 4, '정답: 4. 각 속성의 도메인 수를 모두 곱하면 가능한 튜플 수는 2×3×2=12이다.\n\n**오답 풀이**\n- 1번: 일부 도메인 수만 고려한 값이다.\n- 2번: 도메인 수를 더한 값이며 최대 기수가 아니다.\n- 3번: 도메인이 제한되어 있으므로 셀 수 있다.\n- 4번: 가능한 조합의 수로 맞다.\n\n**보충 개념**\n릴레이션의 최대 기수는 가능한 튜플 조합 수로 계산할 수 있다.',
   '릴레이션 기수', 2, @mock_exam_id, 41, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 릴레이션과 그 구성요소에 대한 설명으로 틀린 것은 무엇인가?\n\n① 릴레이션 스키마와 릴레이션 인스턴스의 결합으로 구성된다.\n② 속성은 개체를 구성하는 고유의 특성이다.\n③ 각 튜플은 순서가 존재하며 중복 없이 고유한 값을 가진다.\n④ 개체에 관한 데이터를 속성과 튜플로 구성된 2차원 테이블의 구조로 표현한 것이다.', 'MCQ', 3, '정답: 3. 릴레이션에서 튜플은 중복되지 않지만 튜플 간 순서는 의미가 없다.\n\n**오답 풀이**\n- 1번: 릴레이션은 스키마와 인스턴스로 구성된다.\n- 2번: 속성은 개체의 특성을 나타낸다.\n- 3번: 튜플 간 순서가 존재한다는 설명이 틀렸다.\n- 4번: 릴레이션은 2차원 테이블 구조로 표현된다.\n\n**보충 개념**\n릴레이션에서 행은 튜플, 열은 속성, 열의 개수는 차수이다.',
   '릴레이션', 1, @mock_exam_id, 42, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '사용하고 있는 데이터가 논리적으로 유일하다고 생각할 수 있는 환경을 제공하는 데이터베이스 투명성은 무엇인가?\n\n① Replication\n② Location\n③ Fragmentation\n④ Failure', 'MCQ', 1, '정답: 1. 중복 투명성은 데이터가 여러 곳에 복제되어 있어도 사용자가 하나의 데이터처럼 인식하게 한다.\n\n**오답 풀이**\n- 1번: Replication Transparency가 해당한다.\n- 2번: Location Transparency는 물리적 위치를 의식하지 않게 한다.\n- 3번: Fragmentation Transparency는 분할 구조를 의식하지 않게 한다.\n- 4번: Failure Transparency는 장애 발생 시에도 일관성을 보장하는 성질이다.\n\n**보충 개념**\n분산 데이터베이스의 투명성에는 위치, 중복, 분할, 장애 투명성 등이 있다.',
   '분산 데이터베이스 투명성', 2, @mock_exam_id, 43, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 OLAP 함수의 종류가 아닌 것은 무엇인가?\n\n① COUNT\n② DELETE\n③ SUM\n④ RANK', 'MCQ', 2, '정답: 2. DELETE는 데이터를 삭제하는 SQL 명령어이며 OLAP 함수가 아니다.\n\n**오답 풀이**\n- 1번: COUNT는 집계 함수이다.\n- 2번: DELETE는 삭제 명령이다.\n- 3번: SUM은 집계 함수이다.\n- 4번: RANK는 순위 함수이다.\n\n**보충 개념**\nOLAP 함수에는 집계 함수, 순위 함수, 행 순서 함수, 그룹 내 비율 함수 등이 있다.',
   'OLAP 함수', 1, @mock_exam_id, 44, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '아래 SQL 문장을 올바르게 해석한 것은 무엇인가?\n\n```sql\nREVOKE SELECT ON lecture FROM jane;\n```\n\n① jane 사용자의 lecture 테이블에 대한 SELECT 권한 확인\n② jane 사용자의 lecture 테이블에 대한 SELECT 권한 부여\n③ jane 사용자의 lecture 테이블에 대한 SELECT 권한 요청\n④ jane 사용자의 lecture 테이블에 대한 SELECT 권한 회수', 'MCQ', 4, '정답: 4. REVOKE는 사용자에게 부여한 권한을 회수하는 명령어이다.\n\n**오답 풀이**\n- 1번: 권한 확인 명령이 아니다.\n- 2번: 권한 부여는 GRANT를 사용한다.\n- 3번: 권한 요청 명령이 아니다.\n- 4번: SELECT 권한을 회수하는 해석이 맞다.\n\n**보충 개념**\nDCL에는 권한 부여를 위한 GRANT와 권한 회수를 위한 REVOKE가 있다.',
   'REVOKE', 1, @mock_exam_id, 45, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '트랜잭션의 특징인 ACID에 대한 설명으로 가장 거리가 먼 것은 무엇인가?\n\n① 트랜잭션 실행 도중 다른 트랜잭션의 영향을 받지 않아야 한다.\n② 시스템 고정 요소는 트랜잭션 이후에도 같아야 한다.\n③ 트랜잭션의 결과는 항상 유지(영구 반영)되어야 한다.\n④ 모든 연산이 수행되거나 선택적으로 수행되어야 한다.', 'MCQ', 4, '정답: 4. 원자성은 모든 연산이 모두 수행되거나 하나도 수행되지 않아야 함을 의미한다.\n\n**오답 풀이**\n- 1번: 고립성에 해당한다.\n- 2번: 일관성과 관련된다.\n- 3번: 지속성에 해당한다.\n- 4번: 선택적으로 수행된다는 설명이 원자성과 맞지 않는다.\n\n**보충 개념**\nACID는 원자성, 일관성, 고립성, 지속성을 의미한다.',
   'ACID', 2, @mock_exam_id, 46, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 수학에서의 교집합(∩) 연산과 같은 역할을 하는 관계 연산은 무엇인가?\n\n① INTERSECT\n② MINUS\n③ UNION\n④ NOT', 'MCQ', 1, '정답: 1. INTERSECT는 두 릴레이션에 공통으로 존재하는 튜플을 반환하는 교집합 연산이다.\n\n**오답 풀이**\n- 1번: INTERSECT는 교집합이다.\n- 2번: MINUS는 차집합이다.\n- 3번: UNION은 합집합이다.\n- 4번: NOT은 여집합 또는 부정 조건과 관련된다.\n\n**보충 개념**\n관계 대수의 집합 연산에는 UNION, INTERSECT, MINUS, CARTESIAN PRODUCT 등이 있다.',
   'INTERSECT', 1, @mock_exam_id, 47, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '로크의 단위가 큰 경우에 해당하지 않는 것은 무엇인가?\n\n① 로크의 개수가 줄어든다.\n② 병행 제어 기법이 단순해진다.\n③ 병행성 수준이 높아진다.\n④ 오버헤드가 감소한다.', 'MCQ', 3, '정답: 3. 로크 단위가 크면 병행성 수준은 낮아진다.\n\n**오답 풀이**\n- 1번: 로크 단위가 크면 로크 개수는 줄어든다.\n- 2번: 로크 관리가 단순해진다.\n- 3번: 병행성 수준은 높아지는 것이 아니라 낮아진다.\n- 4번: 관리 오버헤드는 감소한다.\n\n**보충 개념**\n로크 단위가 작으면 병행성은 높지만 로크 관리 오버헤드가 증가한다.',
   '로킹 단위', 2, @mock_exam_id, 48, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '4개의 속성, 2개의 후보키, 6개의 릴레이션 인스턴스가 존재하는 릴레이션의 차수는 얼마인가?\n\n① 4\n② 2\n③ 6\n④ 알 수 없음', 'MCQ', 1, '정답: 1. 릴레이션의 차수는 속성의 개수이므로 4이다.\n\n**오답 풀이**\n- 1번: 속성이 4개이므로 차수는 4이다.\n- 2번: 후보키 개수이다.\n- 3번: 릴레이션 인스턴스 또는 튜플 수와 관련된다.\n- 4번: 속성 개수가 주어졌으므로 알 수 있다.\n\n**보충 개념**\n릴레이션에서 차수는 열의 수, 카디널리티는 행의 수를 의미한다.',
   '릴레이션 차수', 1, @mock_exam_id, 49, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), 'SQL 문법에서 HAVING 절을 사용하기 위해 함께 사용해야 하는 것은 무엇인가?\n\n① GROUP BY\n② WHERE BY\n③ ORDER BY\n④ JOIN BY', 'MCQ', 1, '정답: 1. HAVING 절은 GROUP BY로 그룹화된 결과에 조건을 적용할 때 사용한다.\n\n**오답 풀이**\n- 1번: GROUP BY가 HAVING과 함께 사용된다.\n- 2번: WHERE BY는 올바른 SQL 절이 아니다.\n- 3번: ORDER BY는 정렬 절이다.\n- 4번: JOIN BY는 올바른 SQL 절이 아니다.\n\n**보충 개념**\nWHERE는 그룹화 전 행 조건, HAVING은 그룹화 후 그룹 조건에 사용된다.',
   'HAVING', 1, @mock_exam_id, 50, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '80점 대의 학생 정보를 조회하고 싶을 때, 적절한 SQL 구문은 무엇인가?\n\n① BETWEEN 80 AND 89\n② BETWEEN 80 AND 90\n③ BETWEEN 80 OR 89\n④ BETWEEN 80 OR 90', 'MCQ', 1, '정답: 1. 80점대는 80 이상 89 이하이므로 BETWEEN 80 AND 89가 적절하다.\n\n**오답 풀이**\n- 1번: 80점대 범위와 일치한다.\n- 2번: 90점까지 포함되어 80점대가 아니다.\n- 3번: BETWEEN은 AND와 함께 사용한다.\n- 4번: BETWEEN은 OR와 함께 사용하지 않는다.\n\n**보충 개념**\nSQL의 BETWEEN A AND B는 A와 B를 모두 포함한다.',
   'BETWEEN', 1, @mock_exam_id, 51, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '아래의 SQL문장을 올바르게 해석한 것은 무엇인가?\n\n```sql\nSELECT 성명, 학년\nFROM 데이터베이스\nWHERE EXISTS (\n  SELECT *\n  FROM 인공지능\n  WHERE 데이터베이스.학번 = 인공지능.학번\n);\n```\n\n① 인공지능 테이블에서, 데이터베이스 수업을 수강하는 학생을 조회\n② 인공지능 테이블에서, 데이터베이스 수업을 수강하지 않는 학생을 조회\n③ 데이터베이스 테이블에서, 인공지능 수업을 수강하는 학생을 조회\n④ 데이터베이스 테이블에서, 인공지능 수업을 수강하지 않는 학생을 조회', 'MCQ', 3, '정답: 3. 외부 테이블은 데이터베이스이며, EXISTS 조건으로 인공지능 테이블에 같은 학번이 존재하는 학생을 조회한다.\n\n**오답 풀이**\n- 1번: 조회 기준 테이블이 인공지능이 아니다.\n- 2번: NOT EXISTS가 아니므로 수강하지 않는 학생이 아니다.\n- 3번: 데이터베이스 테이블에서 인공지능 수업 수강 학생을 조회한다.\n- 4번: NOT EXISTS 조건이 아니다.\n\n**보충 개념**\nEXISTS는 서브쿼리 결과가 존재하는지 여부를 조건으로 판단한다.',
   'EXISTS', 3, @mock_exam_id, 52, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 정규화의 필요성에 해당하지 않는 것은 무엇인가?\n\n① 삽입 이상의 제거\n② 갱신 이상의 제거\n③ 삭제 이상의 제거\n④ 성능 이상의 제거', 'MCQ', 4, '정답: 4. 정규화의 주된 목적은 삽입, 갱신, 삭제 이상을 제거하는 것이다.\n\n**오답 풀이**\n- 1번: 삽입 이상 제거는 정규화의 목적이다.\n- 2번: 갱신 이상 제거는 정규화의 목적이다.\n- 3번: 삭제 이상 제거는 정규화의 목적이다.\n- 4번: 성능 이상 제거는 정규화 필요성으로 보기 어렵다.\n\n**보충 개념**\n정규화는 데이터 중복을 줄이고 이상 현상을 방지하기 위한 설계 과정이다.',
   '정규화', 1, @mock_exam_id, 53, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '제3정규형을 만족시키기 위해 수행해야 하는 작업으로 옳은 것은 무엇인가?\n\n① 부분 함수 종속 제거\n② 다치 종속 제거\n③ 이행적 함수 종속 제거\n④ 조인 종속 제거', 'MCQ', 3, '정답: 3. 제3정규형은 이행적 함수 종속을 제거한 정규형이다.\n\n**오답 풀이**\n- 1번: 부분 함수 종속 제거는 제2정규형과 관련된다.\n- 2번: 다치 종속 제거는 제4정규형과 관련된다.\n- 3번: 이행적 함수 종속 제거가 제3정규형의 핵심이다.\n- 4번: 조인 종속 제거는 제5정규형과 관련된다.\n\n**보충 개념**\n정규화는 1NF, 2NF, 3NF, BCNF, 4NF, 5NF 순으로 진행된다.',
   '제3정규형', 2, @mock_exam_id, 54, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 로그를 이용한 회복 기법에 사용되는 연산이 아닌 것은 무엇인가?\n\n① Undo\n② Redo\n③ Replace\n④ CheckPoint', 'MCQ', 3, '정답: 3. Replace는 로그를 이용한 회복 기법의 대표 연산이 아니다.\n\n**오답 풀이**\n- 1번: Undo는 변경 내용을 취소하여 복원한다.\n- 2번: Redo는 기록된 내용을 다시 반영한다.\n- 3번: Replace는 로그 회복 연산으로 보기 어렵다.\n- 4번: CheckPoint는 회복 기준점으로 사용된다.\n\n**보충 개념**\n로그 기반 회복에는 Undo, Redo, CheckPoint 등이 사용된다.',
   '회복 기법', 1, @mock_exam_id, 55, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 아래에서 설명하는 스토리지 유형은 무엇인가?\n\n**<보기>**\n- Fibre Channel과 같은 고속 네트워크 기술을 사용한다.\n- 대규모 데이터베이스, 고성능 컴퓨팅 등 높은 성능이 요구되는 환경에서 주로 사용된다.\n- 여러 스토리지 장치를 통합 관리하여 데이터 가용성을 높이고, 유연한 확장이 가능하다.\n\n① NAS\n② SAN\n③ DAS\n④ KAS', 'MCQ', 2, '정답: 2. SAN은 Fibre Channel 같은 고속 네트워크를 통해 서버와 스토리지를 연결한다.\n\n**오답 풀이**\n- 1번: NAS는 네트워크 기반 파일 저장소이다.\n- 2번: SAN은 고성능 스토리지 네트워크 방식이다.\n- 3번: DAS는 서버에 저장장치를 직접 연결한다.\n- 4번: KAS는 대표적인 스토리지 유형이 아니다.\n\n**보충 개념**\nSAN은 대규모 데이터베이스와 고성능 컴퓨팅 환경에서 자주 사용된다.',
   'SAN', 1, @mock_exam_id, 56, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '관계 대수에 대한 설명과 가장 거리가 먼 것은 무엇인가?\n\n① 절차적 언어이다.\n② 관계 해석과 관계 대수는 처리 기능 및 능력이 동등하다.\n③ 일반 집합 연산자는 합집합, 교집합, 차집합, 교차곱이 있다.\n④ 일반 집합 연산자와 존재 연산자가 있다.', 'MCQ', 4, '정답: 4. 관계 대수는 일반 집합 연산자와 순수 관계 연산자로 구분한다.\n\n**오답 풀이**\n- 1번: 관계 대수는 절차적 언어이다.\n- 2번: 관계 해석과 관계 대수는 표현 능력이 동등하다.\n- 3번: 일반 집합 연산자에는 합집합, 교집합, 차집합, 교차곱이 있다.\n- 4번: 존재 연산자는 관계 대수의 일반 분류가 아니다.\n\n**보충 개념**\n순수 관계 연산자에는 SELECT, PROJECT, JOIN, DIVISION 등이 있다.',
   '관계 대수', 2, @mock_exam_id, 57, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 데이터베이스의 논리적 설계 단계에서 수행하지 않는 작업은 무엇인가?\n\n① 모든 업무 영역에 대한 개체, 속성, 관계, 프로세스 등을 파악한다.\n② 개념 모델을 컴퓨터가 이해할 수 있는 논리적 구조로 매핑한다.\n③ 목표 시스템에 적용할 수 있는 트랜잭션 인터페이스를 설계한다.\n④ 모든 업무 데이터를 비정규화하여 표현한다.', 'MCQ', 4, '정답: 4. 논리적 설계에서는 업무 데이터를 정규화하여 표현하는 것이 일반적이다.\n\n**오답 풀이**\n- 1번: 개체, 속성, 관계 파악은 논리 설계와 관련된다.\n- 2번: 개념 모델을 논리 구조로 매핑한다.\n- 3번: 트랜잭션 인터페이스 설계가 포함될 수 있다.\n- 4번: 모든 업무 데이터를 비정규화하는 것은 논리적 설계의 일반 작업이 아니다.\n\n**보충 개념**\n논리적 설계는 DBMS에 독립적인 논리 구조를 만들고 정규화를 수행한다.',
   '논리적 설계', 2, @mock_exam_id, 58, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '트랜잭션 분석을 위해 각 테이블에 대한 생성, 조회, 갱신, 삭제 프로세스의 영향도를 테이블 형식으로 표현한 것은 무엇인가?\n\n① Balanced Tree\n② CRUD Matrix\n③ Clustering\n④ Entity Integrity', 'MCQ', 2, '정답: 2. CRUD Matrix는 데이터와 프로세스 간의 생성, 조회, 수정, 삭제 관계를 표로 나타낸다.\n\n**오답 풀이**\n- 1번: Balanced Tree는 균형 트리 자료구조이다.\n- 2번: CRUD Matrix가 정답이다.\n- 3번: Clustering은 관련 데이터를 묶는 기술이다.\n- 4번: Entity Integrity는 개체 무결성이다.\n\n**보충 개념**\nCRUD Matrix는 업무 프로세스와 데이터 간 영향도를 분석하는 데 사용된다.',
   'CRUD Matrix', 1, @mock_exam_id, 59, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중 중복 값을 허용하지 않는 인덱스를 생성하기 위한 옵션은 무엇인가?\n\n① REPLACE\n② NULL\n③ UNIQUE\n④ FORCE', 'MCQ', 3, '정답: 3. UNIQUE 옵션은 중복 값을 허용하지 않는 인덱스를 생성할 때 사용한다.\n\n**오답 풀이**\n- 1번: REPLACE는 문자열 치환 또는 대체와 관련된다.\n- 2번: NULL은 값이 없음을 의미한다.\n- 3번: UNIQUE가 중복 방지 옵션이다.\n- 4번: FORCE는 중복 방지 인덱스 옵션이 아니다.\n\n**보충 개념**\nUNIQUE 제약조건이나 UNIQUE 인덱스는 데이터 중복을 방지한다.',
   'UNIQUE 인덱스', 1, @mock_exam_id, 60, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중 각 작업 노드별 소요 시간이 아래와 같을 때, 주 공정에 소요되는 시간은 얼마인가?\n\n**<그림>**\n<svg xmlns="http://www.w3.org/2000/svg" width="620" height="240" viewBox="0 0 620 240" role="img" aria-label="주 공정 후보 경로 비교"><style>.t{font-size:14px;font-family:Arial,sans-serif;fill:#111}.bar{fill:#e5e7eb;stroke:#333}.axis{stroke:#777}</style><text x="310" y="24" text-anchor="middle" class="t">주 공정 후보 경로별 소요 시간</text><text x="20" y="70" class="t">A → B → D → F → H</text><rect x="200" y="55" width="360" height="24" class="bar"/><text x="570" y="72" class="t">12</text><text x="20" y="110" class="t">A → B → E → F → H</text><rect x="200" y="95" width="300" height="24" class="bar"/><text x="510" y="112" class="t">10</text><text x="20" y="150" class="t">A → C → G → H</text><rect x="200" y="135" width="330" height="24" class="bar"/><text x="540" y="152" class="t">11</text><line x1="200" y1="200" x2="560" y2="200" class="axis"/><text x="200" y="220" class="t">0</text><text x="560" y="220" class="t">12</text></svg>\n\n① 10\n② 11\n③ 12\n④ 22', 'MCQ', 3, '정답: 3. 주 공정은 가능한 경로 중 소요 시간이 가장 긴 경로이며 제시된 네트워크의 주 공정 소요 시간은 12이다.\n\n**오답 풀이**\n- 1번: 10은 최장 경로 시간이 아니다.\n- 2번: 11은 최장 경로 시간이 아니다.\n- 3번: 12가 주 공정 소요 시간이다.\n- 4번: 22는 경로 계산 결과와 맞지 않는다.\n\n**보충 개념**\nCPM에서 임계 경로가 지연되면 전체 프로젝트 일정도 지연된다.',
   'CPM', 3, @mock_exam_id, 61, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '새로운 프로세스를 생성하는 UNIX 명령어는 무엇인가?\n\n① find\n② fork\n③ mount\n④ grep', 'MCQ', 2, '정답: 2. fork는 현재 프로세스를 복제하여 새로운 프로세스를 생성한다.\n\n**오답 풀이**\n- 1번: find는 파일 검색 명령어이다.\n- 2번: fork는 프로세스 생성과 관련된다.\n- 3번: mount는 파일 시스템을 연결하는 명령이다.\n- 4번: grep은 문자열 패턴을 검색하는 명령이다.\n\n**보충 개념**\nUNIX 계열 시스템에서 프로세스 생성은 fork 시스템 호출을 통해 이루어진다.',
   'UNIX fork', 1, @mock_exam_id, 62, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중 그룹은 쓰기 권한을 제거하고 일반 사용자는 쓰기, 실행 권한을 제거하는 umask 값은 무엇인가?\n\n① 421\n② 754\n③ 012\n④ 023', 'MCQ', 4, '정답: 4. 그룹의 쓰기 권한 제거는 2이고 일반 사용자의 쓰기와 실행 권한 제거는 3이므로 umask는 023이다.\n\n**오답 풀이**\n- 1번: 제거할 권한 조합과 맞지 않는다.\n- 2번: 과도하게 많은 권한을 제거한다.\n- 3번: 그룹 권한 제거 위치가 맞지 않는다.\n- 4번: 소유자 0, 그룹 2, 기타 3으로 조건과 일치한다.\n\n**보충 개념**\numask는 새 파일이나 디렉터리를 만들 때 기본 권한에서 제거할 권한을 지정한다.',
   'umask', 3, @mock_exam_id, 63, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 Java 코드의 수행 결과로 옳은 것은 무엇인가?\n\n```java\npublic class Main {\n    public static int mth(int a) { return a * 3; }\n    public static int mth(int a, int b) { return a * b - 2; }\n    public static int mth(int a, int b, int c) { return a + b * c; }\n    public static void main(String[] args) {\n        int v = mth(4, 5);\n        System.out.println(v);\n    }\n}\n```\n\n① 15\n② 12\n③ 18\n④ 30', 'MCQ', 3, '정답: 3. 인수 2개짜리 mth(int a, int b)가 호출되어 4×5-2=18이 출력된다.\n\n**오답 풀이**\n- 1번: 인수 1개짜리 메서드 결과가 아니다.\n- 2번: 계산식과 맞지 않는다.\n- 3번: 4×5-2의 결과이다.\n- 4번: 인수 3개짜리 메서드가 호출되지 않는다.\n\n**보충 개념**\n메서드 오버로딩은 인수의 개수나 타입에 따라 호출할 메서드를 결정한다.',
   'Java 오버로딩', 2, @mock_exam_id, 64, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '프로세스별 실행 시간과 도착 시간이 아래와 같을 때, SJF 스케줄링을 적용한다면 가장 먼저 작업이 완료되는 프로세스는 무엇인가?\n\n| 프로세스 | 실행 시간 | 도착 시간 |\n|---|---:|---:|\n| A | 20 | 3 |\n| B | 15 | 0 |\n| C | 10 | 5 |\n| D | 17 | 2 |\n\n① A\n② B\n③ C\n④ D', 'MCQ', 2, '정답: 2. 비선점 SJF에서는 0시점에 도착한 B가 먼저 실행되어 가장 먼저 완료된다.\n\n**오답 풀이**\n- 1번: A는 3시점에 도착하므로 처음 실행될 수 없다.\n- 2번: B는 0시점에 도착하여 먼저 실행된다.\n- 3번: C는 실행 시간은 짧지만 5시점에 도착한다.\n- 4번: D는 2시점에 도착한다.\n\n**보충 개념**\nSJF는 준비 큐에 있는 프로세스 중 실행 시간이 가장 짧은 프로세스를 선택한다.',
   'SJF', 3, @mock_exam_id, 65, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 Python 코드를 실행하여 출력되는 결과에 포함되는 None 값의 개수는?\n\n```python\ndef fn(s):\n    if s[0] == "김":\n        return s\n\nstring = "김진수,강하영,김소연,박영진,김가을"\na = string.split(",")\nb = list(map(fn, a))\nprint(b)\n```\n\n① 1\n② 2\n③ 3\n④ 4', 'MCQ', 2, '정답: 2. 강하영과 박영진은 첫 글자가 김이 아니므로 함수가 값을 반환하지 않아 None이 된다.\n\n**오답 풀이**\n- 1번: 김이 아닌 이름은 2개이다.\n- 2번: None은 2개 발생한다.\n- 3번: 김으로 시작하는 이름은 3개이다.\n- 4번: 김이 아닌 이름이 4개가 아니다.\n\n**보충 개념**\nPython 함수에서 return이 실행되지 않으면 기본적으로 None을 반환한다.',
   'Python map', 2, @mock_exam_id, 66, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래에서 설명하는 해결 방안은 무엇인가?\n\n**<보기>**\n- 안정적 상태를 유지할 수 있는 프로세스의 요청만 받아들이는 방식이다.\n- 대표적으로 은행원 알고리즘(Banker''s Algorithm)이 있다.\n\n① Prevention\n② Detection\n③ Avoidance\n④ Recovery', 'MCQ', 3, '정답: 3. 은행원 알고리즘은 교착상태 회피(Avoidance) 기법이다.\n\n**오답 풀이**\n- 1번: Prevention은 교착상태 발생 조건을 사전에 부정하는 방식이다.\n- 2번: Detection은 교착상태 발생 여부를 탐지한다.\n- 3번: Avoidance는 안전 상태를 유지하는 요청만 허용한다.\n- 4번: Recovery는 교착상태 발생 후 복구하는 방식이다.\n\n**보충 개념**\n교착상태 처리 기법에는 예방, 회피, 탐지, 회복이 있다.',
   '교착상태 회피', 2, @mock_exam_id, 67, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 Python 코드의 수행 결과로 옳은 것은 무엇인가?\n\n```python\na = 10\nb = 20\ndef fn(n):\n    a = n\nfn(30)\nprint(a)\n```\n\n① 10\n② 20\n③ 30\n④ 오류', 'MCQ', 1, '정답: 1. 함수 내부의 a는 지역 변수이므로 전역 변수 a는 10으로 유지된다.\n\n**오답 풀이**\n- 1번: 전역 변수 a의 값이 출력된다.\n- 2번: b는 출력 대상이 아니다.\n- 3번: 함수 내부 지역 변수 값은 전역 a를 바꾸지 않는다.\n- 4번: 문법 오류가 발생하지 않는다.\n\n**보충 개념**\nPython에서 함수 내부 대입은 기본적으로 지역 변수에 대한 대입이다.',
   'Python 변수 범위', 2, @mock_exam_id, 68, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '디자인 패턴을 소프트웨어 개발에 적용함으로써 얻게 되는 이점이 아닌 것은 무엇인가?\n\n① 유지보수성이 증가한다.\n② 협업의 효율성이 증대된다.\n③ 모든 언어에 적용 가능하다.\n④ 시스템의 확장성이 향상된다.', 'MCQ', 3, '정답: 3. 디자인 패턴은 주로 객체지향 설계에서 활용되며 모든 언어에 그대로 적용 가능하다고 보기 어렵다.\n\n**오답 풀이**\n- 1번: 디자인 패턴은 유지보수성 향상에 도움을 준다.\n- 2번: 공통 설계 어휘를 제공해 협업 효율을 높인다.\n- 3번: 모든 언어에 적용 가능하다는 설명은 과도하다.\n- 4번: 확장성 향상에 도움이 된다.\n\n**보충 개념**\n디자인 패턴은 반복되는 설계 문제에 대한 재사용 가능한 해결책이다.',
   '디자인 패턴', 1, @mock_exam_id, 69, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 C 코드의 for문을 while문으로 올바르게 변환한 것은 무엇인가?\n\n```c\nfor(i = 0; i < 10; i++) {\n    sum += i;\n}\n```\n\n① i=0;\nwhile(i<10){\n    i++;\n    sum+=i;\n}\n② i=0;\nwhile(i<10){\n    sum+=i;\n    i++;\n}\n③ i=0;\nwhile(i<10){\n    sum+=i;\n}\ni++;\n④ i=0;\ni++;\nwhile(i<10){\n    sum+=i;\n}', 'MCQ', 2, '정답: 2. for문의 초기식, 조건식, 본문, 증감식 순서를 while문으로 옮기면 2번이 된다.\n\n**오답 풀이**\n- 1번: i를 먼저 증가시켜 원래 반복과 결과가 달라진다.\n- 2번: 원래 for문과 같은 흐름이다.\n- 3번: i++가 반복문 밖에 있어 무한 반복 가능성이 있다.\n- 4번: 반복 시작 전 i를 증가시켜 결과가 다르다.\n\n**보충 개념**\nfor문은 초기식 → 조건 검사 → 본문 실행 → 증감식 순서로 동작한다.',
   'C 반복문', 2, @mock_exam_id, 70, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중 객체지향 설계 원칙에 해당하지 않는 것은 무엇인가?\n\n① Super Responsibility\n② Open-Closed\n③ Liskov Substitution\n④ Interface Segregation', 'MCQ', 1, '정답: 1. SOLID의 S는 Single Responsibility Principle이며 Super Responsibility가 아니다.\n\n**오답 풀이**\n- 1번: Super Responsibility는 객체지향 설계 원칙 명칭이 아니다.\n- 2번: Open-Closed는 개방-폐쇄 원칙이다.\n- 3번: Liskov Substitution은 리스코프 치환 원칙이다.\n- 4번: Interface Segregation은 인터페이스 분리 원칙이다.\n\n**보충 개념**\nSOLID는 단일 책임, 개방-폐쇄, 리스코프 치환, 인터페이스 분리, 의존 역전 원칙을 의미한다.',
   'SOLID', 1, @mock_exam_id, 71, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중 UDP에 대한 설명과 가장 거리가 먼 것은 무엇인가?\n\n① 흐름 제어 및 순서 제어가 없어 전송 속도는 빠르지만 신뢰성 보장이 어렵다.\n② 신뢰성을 보장하지 않는 연결성 통신을 제공한다.\n③ 하나의 정보를 다수의 인원이 수신해야 하는 경우에 적합한 프로토콜이다.\n④ 신뢰성 제공을 위한 기능이 없어 상대적으로 간단한 프레임 구조를 가진다.', 'MCQ', 2, '정답: 2. UDP는 연결성이 아니라 비연결성 통신을 제공한다.\n\n**오답 풀이**\n- 1번: UDP는 흐름 제어와 순서 제어가 없어 빠르지만 신뢰성이 낮다.\n- 2번: 연결성 통신이라는 설명이 틀렸다.\n- 3번: 멀티캐스트 등에 적합할 수 있다.\n- 4번: 구조가 단순하다.\n\n**보충 개념**\nUDP는 비연결형 전송 계층 프로토콜이며 속도가 중요한 서비스에 사용된다.',
   'UDP', 2, @mock_exam_id, 72, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), 'C 코드에서 정수 타입과 그 크기가 잘못 짝지어진 것은?\n\n① char - 1\n② short - 2\n③ int - 4\n④ long - 6', 'MCQ', 4, '정답: 4. long 타입은 시스템 환경에 따라 4 또는 8바이트로 사용되며 6바이트로 고정되지 않는다.\n\n**오답 풀이**\n- 1번: char는 일반적으로 1바이트이다.\n- 2번: short는 일반적으로 2바이트이다.\n- 3번: int는 일반적으로 4바이트이다.\n- 4번: long - 6은 잘못된 짝이다.\n\n**보충 개념**\nC 자료형의 크기는 구현 환경에 따라 달라질 수 있다.',
   'C 자료형', 1, @mock_exam_id, 73, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), 'C 코드에서 break의 역할에 대한 설명으로 가장 옳지 않은 것은?\n\n① (무한)루프문을 벗어날 때 사용한다.\n② switch~case문에서 중지점을 지정할 때 사용한다.\n③ 모든 선택문, 제어문에서 사용 가능하다.\n④ 해당 지역의 반복문을 벗어날 수 있다.', 'MCQ', 3, '정답: 3. break는 모든 선택문과 제어문에서 사용할 수 있는 것이 아니라 주로 반복문과 switch문에서 사용된다.\n\n**오답 풀이**\n- 1번: 반복문을 벗어날 때 사용할 수 있다.\n- 2번: switch-case에서 흐름을 중단할 때 사용한다.\n- 3번: 모든 선택문, 제어문에서 사용할 수 있다는 설명은 틀렸다.\n- 4번: 현재 반복문을 벗어날 수 있다.\n\n**보충 개념**\nbreak는 가장 가까운 반복문이나 switch문을 종료한다.',
   'C break', 1, @mock_exam_id, 74, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중 IPv4에서 C클래스에 해당하지 않는 주소는 무엇인가?\n\n① 192.168.0.1\n② 223.255.255.254\n③ 128.0.1.100\n④ 200.100.200.15', 'MCQ', 3, '정답: 3. C 클래스 주소 범위는 192.0.0.0부터 223.255.255.255까지이다.\n\n**오답 풀이**\n- 1번: 192.168.0.1은 C 클래스 범위에 포함된다.\n- 2번: 223.255.255.254는 C 클래스 범위에 포함된다.\n- 3번: 128.0.1.100은 B 클래스 범위이다.\n- 4번: 200.100.200.15는 C 클래스 범위에 포함된다.\n\n**보충 개념**\nIPv4 클래스ful 주소에서 A는 1~126, B는 128~191, C는 192~223 범위를 사용한다.',
   'IPv4 클래스', 2, @mock_exam_id, 75, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '파일 디스크립터(File Descriptor)라고도 하며 운영체제가 특정 파일에 접근할 때 파악되어야 할 파일의 관리 정보를 저장해 준 블록을 의미하는 것은 무엇인가?\n\n① FCB\n② KBF\n③ FDT\n④ ACR', 'MCQ', 1, '정답: 1. FCB(File Control Block)는 파일 관리 정보를 저장하는 제어 블록이다.\n\n**오답 풀이**\n- 1번: FCB가 파일 제어 블록이다.\n- 2번: KBF는 해당 용어로 보기 어렵다.\n- 3번: FDT는 문제의 설명과 직접 일치하지 않는다.\n- 4번: ACR은 파일 제어 블록이 아니다.\n\n**보충 개념**\nFCB는 파일 이름, 위치, 크기, 접근 권한 등 파일 관리 정보를 포함한다.',
   'FCB', 1, @mock_exam_id, 76, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '3개의 빈 프레임과 [2,2,3,1,3,2,4,3,3,5]의 페이지 참조열을 가진 상황에서 FIFO 알고리즘을 적용했을 때의 페이지 부재 횟수는?\n\n① 4\n② 5\n③ 6\n④ 7', 'MCQ', 2, '정답: 2. FIFO 페이지 교체를 적용하면 페이지 부재가 총 5회 발생한다.\n\n**오답 풀이**\n- 1번: 일부 페이지 부재가 누락된 값이다.\n- 2번: FIFO 적용 결과와 일치한다.\n- 3번: 필요 이상으로 페이지 부재를 계산한 값이다.\n- 4번: 필요 이상으로 페이지 부재를 계산한 값이다.\n\n**보충 개념**\nFIFO는 가장 먼저 적재된 페이지를 가장 먼저 교체하는 페이지 교체 알고리즘이다.',
   'FIFO 페이지 교체', 3, @mock_exam_id, 77, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '전송 계층 중 TCP에서 사용되는 데이터 단위는 무엇인가?\n\n① 비트\n② 데이터그램\n③ 세그먼트\n④ 프레임', 'MCQ', 3, '정답: 3. TCP에서 사용하는 전송 계층 데이터 단위는 세그먼트이다.\n\n**오답 풀이**\n- 1번: 비트는 물리 계층의 데이터 단위이다.\n- 2번: 데이터그램은 UDP와 관련된다.\n- 3번: TCP의 PDU는 세그먼트이다.\n- 4번: 프레임은 데이터 링크 계층의 데이터 단위이다.\n\n**보충 개념**\nOSI 계층별 PDU는 비트, 프레임, 패킷, 세그먼트 등으로 구분된다.',
   'TCP 세그먼트', 1, @mock_exam_id, 78, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래의 Java 코드를 수행한 결과로 옳은 것은?\n\n```java\npublic class Main {\n    public static void main(String[] args) {\n        int a = 17;\n        int b = a % 2 == 0 ? a : 0;\n        if (b < 17) {\n            System.out.println("a");\n        } else {\n            System.out.println("b");\n        }\n    }\n}\n```\n\n① a\n② b\n③ 17\n④ 오류', 'MCQ', 1, '정답: 1. a는 17로 홀수이므로 b에는 0이 저장되고, b < 17 조건이 참이어서 a가 출력된다.\n\n**오답 풀이**\n- 1번: 실행 결과와 일치한다.\n- 2번: else 블록은 실행되지 않는다.\n- 3번: 숫자 17을 출력하는 코드가 아니다.\n- 4번: 문법 오류가 발생하지 않는다.\n\n**보충 개념**\n삼항 연산자는 조건식 ? 참일 때 값 : 거짓일 때 값 형식으로 동작한다.',
   'Java 삼항 연산자', 2, @mock_exam_id, 79, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 C 코드의 수행 결과로 옳은 것은?\n\n```c\n#include <stdio.h>\nint main() {\n    int a = 10, b = 0, c = 0;\n    while (a-- > b) {\n        b++;\n        c++;\n    }\n    printf("%d", c);\n    return 0;\n}\n```\n\n① 4\n② 5\n③ 6\n④ 7', 'MCQ', 2, '정답: 2. 조건 검사 후 a가 감소하고 반복마다 b와 c가 증가하여 총 5회 반복된다.\n\n**오답 풀이**\n- 1번: 반복 횟수를 하나 적게 계산한 값이다.\n- 2번: c는 5가 된다.\n- 3번: 반복 횟수를 하나 많게 계산한 값이다.\n- 4번: 반복 조건을 잘못 추적한 값이다.\n\n**보충 개념**\n후위 감소 연산자는 현재 값을 먼저 비교에 사용한 뒤 값을 감소시킨다.',
   'C 증감 연산자', 4, @mock_exam_id, 80, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '아래에서 설명하는 네트워크 관련 용어는 무엇인가?\n\n**<보기>**\n- 긍정 응답을 기다리지 않고 사용 중인 채널에 일정한 규칙을 통하여 접근하는 방식이다.\n- 충돌 검출, 재송신 기능이 포함된다.\n- IEEE 802.3 프로토콜을 사용한다.\n\n① CSMA/CD\n② ALOHA\n③ STDM\n④ ATDM', 'MCQ', 1, '정답: 1. CSMA/CD는 이더넷에서 사용되는 충돌 감지 방식의 매체 접근 제어 기법이다.\n\n**오답 풀이**\n- 1번: CSMA/CD가 설명과 일치한다.\n- 2번: ALOHA는 단말이 임의로 전송하는 방식이다.\n- 3번: STDM은 동기식 시분할 다중화이다.\n- 4번: ATDM은 비동기식 시분할 다중화이다.\n\n**보충 개념**\nCSMA/CD는 충돌을 감지하면 재전송을 수행하는 이더넷 접근 방식이다.',
   'CSMA/CD', 2, @mock_exam_id, 81, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '192.168.123.0/24의 네트워크를 6개의 서브 네트워크로 나누었을 때, 2번째 네트워크의 1번째 사용 가능한 IP주소는 무엇인가?\n\n① 192.168.123.32\n② 192.168.123.33\n③ 192.168.123.64\n④ 192.168.123.65', 'MCQ', 2, '정답: 2. /24에서 6개 이상의 서브넷을 만들려면 /27이 필요하고, 2번째 네트워크 192.168.123.32/27의 첫 사용 가능 호스트는 192.168.123.33이다.\n\n**오답 풀이**\n- 1번: 2번째 네트워크의 네트워크 주소이므로 호스트로 사용할 수 없다.\n- 2번: 2번째 네트워크의 첫 사용 가능 호스트 주소이다.\n- 3번: 3번째 네트워크의 네트워크 주소이다.\n- 4번: 3번째 네트워크의 첫 사용 가능 호스트 주소이다.\n\n**보충 개념**\n6개 이상의 서브넷이 필요하면 호스트 비트에서 3비트를 빌려 /27(서브넷 8개)로 분할한다. 각 /27 서브넷은 32개 주소 중 네트워크/브로드캐스트를 제외한 30개 호스트를 가진다.',
   '서브넷팅', 4, @mock_exam_id, 82, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '웹 페이지에 악의적인 스크립트를 포함시켜 사용자 측에서 실행되게끔 유도하는 공격 기법은 무엇인가?\n\n① Smurf Attack\n② Cross-Site Request Forgery\n③ Ping of Death\n④ Cross-Site Scripting', 'MCQ', 4, '정답: 4. Cross-Site Scripting은 악성 스크립트를 웹 페이지에 삽입해 사용자 브라우저에서 실행시키는 공격이다.\n\n**오답 풀이**\n- 1번: Smurf Attack은 ICMP를 악용한 DoS 공격이다.\n- 2번: CSRF는 사용자의 요청을 위조하는 공격이다.\n- 3번: Ping of Death는 비정상적으로 큰 ICMP 패킷을 이용한 공격이다.\n- 4번: XSS가 설명과 일치한다.\n\n**보충 개념**\nXSS는 입력값 검증과 출력 인코딩을 통해 방어할 수 있다.',
   'XSS', 1, @mock_exam_id, 83, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'DES를 대체하는 미국의 표준 대칭키 블록 알고리즘은 무엇인가?\n\n① SEED\n② IDEA\n③ AES\n④ ARIA', 'MCQ', 3, '정답: 3. AES는 DES를 대체하기 위해 채택된 미국 표준 대칭키 블록 암호 알고리즘이다.\n\n**오답 풀이**\n- 1번: SEED는 국내에서 개발된 대칭키 암호 알고리즘이다.\n- 2번: IDEA는 스위스에서 개발된 암호 알고리즘이다.\n- 3번: AES가 DES를 대체한 미국 표준이다.\n- 4번: ARIA는 국내에서 개발된 대칭키 암호 알고리즘이다.\n\n**보충 개념**\nAES는 128비트 블록 크기를 사용하는 대표적인 대칭키 블록 암호이다.',
   'AES', 1, @mock_exam_id, 84, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'TCP 헤더의 구성 요소 중, 무결성 보장을 위한 에러 검출에 사용되는 영역은 무엇인가?\n\n① Destination Port\n② Reserved\n③ Urgent Point\n④ Checksum', 'MCQ', 4, '정답: 4. Checksum은 전송 중 오류 검출을 위해 사용되는 필드이다.\n\n**오답 풀이**\n- 1번: Destination Port는 목적지 포트 번호이다.\n- 2번: Reserved는 예약 필드이다.\n- 3번: Urgent Point는 긴급 데이터 처리와 관련된다.\n- 4번: Checksum은 오류 검출에 사용된다.\n\n**보충 개념**\nTCP 헤더에는 포트 번호, 순서 번호, 확인 번호, 제어 비트, 체크섬 등이 포함된다.',
   'TCP Checksum', 1, @mock_exam_id, 85, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '시스템의 파일 무결성을 검사하여 파일이 무단으로 변경되었는지 여부를 확인하는 보안 도구로, 크래커의 침입이나 백도어 생성 여부, 설정 파일의 변경 여부를 체크하는 것은 무엇인가?\n\n① TripWire\n② Trusted OS\n③ Firewall\n④ Root Kit', 'MCQ', 1, '정답: 1. TripWire는 파일 무결성을 검사하여 변경 여부를 탐지하는 보안 도구이다.\n\n**오답 풀이**\n- 1번: TripWire가 설명과 일치한다.\n- 2번: Trusted OS는 보안 기능을 강화한 운영체제이다.\n- 3번: Firewall은 네트워크 접근 제어 장치이다.\n- 4번: Root Kit은 침입 흔적을 숨기는 악성 도구 모음이다.\n\n**보충 개념**\n파일 무결성 검사는 중요 시스템 파일의 변경 여부를 탐지하는 데 사용된다.',
   'TripWire', 1, @mock_exam_id, 86, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 전송 회선의 대역폭을 다수의 작은 채널로 분할하여 동시에 이용하는 다중화기 방식은 무엇인가?\n\n① TDM\n② FDM\n③ CDM\n④ WDM', 'MCQ', 2, '정답: 2. FDM은 주파수 대역을 여러 채널로 나누어 동시에 전송하는 방식이다.\n\n**오답 풀이**\n- 1번: TDM은 시간을 나누어 사용하는 방식이다.\n- 2번: FDM은 대역폭을 주파수별로 나눈다.\n- 3번: CDM은 코드를 이용해 구분한다.\n- 4번: WDM은 광 파장을 나누어 사용하는 방식이다.\n\n**보충 개념**\n다중화는 하나의 전송 매체를 여러 신호가 공유하도록 하는 기술이다.',
   'FDM', 1, @mock_exam_id, 87, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '데이터 센터 전체를 운영하는 소프트웨어가 필요한 기능 및 규모에 따라 동적으로 하드웨어 자원을 할당, 관리하는 역할을 수행하는 데이터 센터는 무엇인가?\n\n① PaaS\n② SDDC\n③ Mesh Network\n④ Data Warehouse', 'MCQ', 2, '정답: 2. SDDC는 데이터 센터 자원을 소프트웨어로 정의하고 동적으로 할당·관리하는 구조이다.\n\n**오답 풀이**\n- 1번: PaaS는 개발 플랫폼을 서비스로 제공한다.\n- 2번: SDDC가 설명과 일치한다.\n- 3번: Mesh Network는 그물망 형태 네트워크이다.\n- 4번: Data Warehouse는 분석용 통합 데이터 저장소이다.\n\n**보충 개념**\nSDDC는 서버, 스토리지, 네트워크 등 데이터 센터 자원을 소프트웨어로 제어한다.',
   'SDDC', 1, @mock_exam_id, 88, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'OSI 7 계층 중, 네트워크 계층에 해당하지 않는 프로토콜은 무엇인가?\n\n① ARP\n② RARP\n③ IP\n④ TCP', 'MCQ', 4, '정답: 4. TCP는 전송 계층 프로토콜이다.\n\n**오답 풀이**\n- 1번: ARP는 네트워크 계층과 데이터링크 계층 사이의 주소 해석과 관련된다.\n- 2번: RARP는 주소 변환과 관련된다.\n- 3번: IP는 네트워크 계층 프로토콜이다.\n- 4번: TCP는 전송 계층에 해당한다.\n\n**보충 개념**\n네트워크 계층은 IP 주소 기반 라우팅과 패킷 전달을 담당한다.',
   'OSI 계층', 1, @mock_exam_id, 89, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'IPv6의 주소 표현 중 올바르지 못한 것은 무엇인가?\n\n① 2001:0db8:85a3:1234:5678:9ABC:DEFG:HIJK\n② 2001:0db8:85a3:0000:0000:8a2e:0370:7334\n③ 2001:0db8:85a3::8a2e:0370:7334\n④ ::1:2', 'MCQ', 1, '정답: 1. IPv6 주소는 16진수로 표현하므로 G, H, I, J, K는 사용할 수 없다.\n\n**오답 풀이**\n- 1번: 16진수 범위를 벗어난 문자가 포함되어 있다.\n- 2번: 올바른 IPv6 표현이다.\n- 3번: 0 축약 표현을 사용한 올바른 IPv6 표현이다.\n- 4번: 축약 표현으로 사용할 수 있다.\n\n**보충 개념**\nIPv6는 128비트 주소를 16진수와 콜론으로 표현한다.',
   'IPv6', 2, @mock_exam_id, 90, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '보안에 취약한 구조를 가진 IP를 개선하기 위해 국제 인터넷 기술 위원회(IETF)에서 설계한 표준은 무엇인가?\n\n① DNS\n② ICMP\n③ IPSec\n④ ARP', 'MCQ', 3, '정답: 3. IPSec은 IP 계층에서 인증과 암호화를 제공하기 위해 설계된 보안 표준이다.\n\n**오답 풀이**\n- 1번: DNS는 도메인 이름을 IP 주소로 변환한다.\n- 2번: ICMP는 오류 메시지와 제어 메시지를 전달한다.\n- 3번: IPSec이 IP 보안 표준이다.\n- 4번: ARP는 IP 주소를 MAC 주소로 변환한다.\n\n**보충 개념**\nIPSec은 AH와 ESP 등을 통해 IP 패킷의 인증, 무결성, 기밀성을 제공한다.',
   'IPSec', 1, @mock_exam_id, 91, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '스니핑 공격의 한 종류로, 위조된 MAC 주소를 지속적으로 네트워크에 흘려 스위치의 주소 테이블을 오버플로우 시키는 방식의 공격 기법은?\n\n① Switch Jamming\n② ARP Spoofing\n③ ARP Redirect\n④ ICMP Redirect', 'MCQ', 1, '정답: 1. Switch Jamming은 스위치의 MAC 주소 테이블을 오버플로우시켜 스니핑을 유도하는 공격이다.\n\n**오답 풀이**\n- 1번: Switch Jamming이 설명과 일치한다.\n- 2번: ARP Spoofing은 ARP 정보를 속이는 공격이다.\n- 3번: ARP Redirect는 ARP 캐시 정보를 변조하는 공격이다.\n- 4번: ICMP Redirect는 라우팅 경로를 변조하는 공격이다.\n\n**보충 개념**\n스위치 재밍은 스위치를 허브처럼 동작하게 만들어 트래픽 도청 가능성을 높인다.',
   'Switch Jamming', 2, @mock_exam_id, 92, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '아래 이미지와 같은 방식의 블록 암호화 운용 방식은 무엇인가?\n\n**<그림>**\n<svg xmlns="http://www.w3.org/2000/svg" width="680" height="220" viewBox="0 0 680 220" role="img" aria-label="CBC 블록 암호화 운용 방식"><style>.box{fill:#fff;stroke:#333;stroke-width:2}.txt{font-size:14px;font-family:Arial,sans-serif;text-anchor:middle;dominant-baseline:middle}.line{stroke:#333;stroke-width:2;fill:none;marker-end:url(#a)}</style><defs><marker id="a" markerWidth="10" markerHeight="10" refX="9" refY="3" orient="auto"><path d="M0,0 L0,6 L9,3 z" fill="#333"/></marker></defs><text x="70" y="55" class="txt">IV</text><circle cx="145" cy="55" r="16" class="box"/><text x="145" y="55" class="txt">XOR</text><rect x="200" y="35" width="95" height="40" class="box"/><text x="247" y="55" class="txt">Encrypt</text><text x="350" y="55" class="txt">C1</text><circle cx="435" cy="55" r="16" class="box"/><text x="435" y="55" class="txt">XOR</text><rect x="490" y="35" width="95" height="40" class="box"/><text x="537" y="55" class="txt">Encrypt</text><text x="625" y="55" class="txt">C2</text><text x="145" y="115" class="txt">P1</text><text x="435" y="115" class="txt">P2</text><path d="M85 55 L128 55" class="line"/><path d="M145 99 L145 72" class="line"/><path d="M161 55 L200 55" class="line"/><path d="M295 55 L350 55" class="line"/><path d="M350 55 L419 55" class="line"/><path d="M435 99 L435 72" class="line"/><path d="M451 55 L490 55" class="line"/><path d="M585 55 L625 55" class="line"/></svg>\n\n① ECB\n② AAC\n③ CBC\n④ KGB', 'MCQ', 3, '정답: 3. CBC는 이전 암호문 블록을 다음 평문 블록과 XOR한 뒤 암호화하는 방식이다.\n\n**오답 풀이**\n- 1번: ECB는 각 블록을 독립적으로 암호화한다.\n- 2번: AAC는 표준 블록 암호 운용 모드가 아니다.\n- 3번: CBC가 그림의 연쇄 구조와 일치한다.\n- 4번: KGB는 표준 블록 암호 운용 모드가 아니다.\n\n**보충 개념**\nCBC는 첫 블록에 초기화 벡터(IV)를 사용하고 이후 블록은 이전 암호문과 연쇄된다.',
   'CBC', 2, @mock_exam_id, 93, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '이산대수의 난해성에 기반한 공개키 암호화 알고리즘은 무엇인가?\n\n① RSA\n② DSA\n③ ECC\n④ DES', 'MCQ', 3, '정답: 3. ECC는 타원곡선 이산대수 문제의 어려움에 기반한 공개키 암호 알고리즘이다.\n\n**오답 풀이**\n- 1번: RSA는 큰 수의 소인수분해 어려움에 기반한다.\n- 2번: DSA는 전자서명 알고리즘이다.\n- 3번: ECC가 이산대수 난해성과 관련된다.\n- 4번: DES는 대칭키 블록 암호이다.\n\n**보충 개념**\n공개키 암호는 수학적으로 풀기 어려운 문제를 보안성의 기반으로 삼는다.',
   'ECC', 2, @mock_exam_id, 94, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '아래 표는 접근 통제 정책을 정리한 것이다. 빈칸 (가), (나), (다)에 해당하는 용어를 올바르게 나열한 것은 무엇인가?\n\n| 구분 | (가) | (나) | (다) |\n|---|---|---|---|\n| 권한 부여 | 시스템 | 데이터 소유자 | 중앙 관리자 |\n| 접근 결정 | 보안 등급(Level) | 신분(Identity) | 역할(Role) |\n| 정책 변경 | 고정적 | 변경 용이 | 변경 용이 |\n| 장점 | 안정적, 중앙집중적 | 구현 용이, 유연함 | 관리 용이 |\n\n① DAC, RBAC, MAC\n② MAC, DAC, RBAC\n③ MAC, RBAC, DAC\n④ RBAC, MAC, DAC', 'MCQ', 2, '정답: 2. 보안 등급 기반은 MAC, 신분 기반은 DAC, 역할 기반은 RBAC이다.\n\n**오답 풀이**\n- 1번: MAC, DAC, RBAC의 순서와 다르다.\n- 2번: 올바른 조합이다.\n- 3번: DAC와 RBAC의 위치가 바뀌었다.\n- 4번: 세 정책의 위치가 모두 맞지 않는다.\n\n**보충 개념**\nMAC은 강제 접근 통제, DAC은 임의 접근 통제, RBAC은 역할 기반 접근 통제이다.',
   '접근 통제', 3, @mock_exam_id, 95, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '바이러스처럼 다른 파일에 기생하지 않고 독립적으로 자신을 복제하여 확산시키는 악성코드는 무엇인가?\n\n① Trojan Horse\n② Key Logger\n③ SpyWare\n④ Worm', 'MCQ', 4, '정답: 4. Worm은 다른 파일에 기생하지 않고 독립적으로 자기 복제하여 확산되는 악성코드이다.\n\n**오답 풀이**\n- 1번: Trojan Horse는 정상 파일처럼 위장하는 악성코드이다.\n- 2번: Key Logger는 키 입력을 기록하는 악성 프로그램이다.\n- 3번: SpyWare는 사용자 정보를 몰래 수집한다.\n- 4번: Worm이 설명과 일치한다.\n\n**보충 개념**\n웜은 네트워크를 통해 빠르게 확산될 수 있어 패치와 네트워크 보안이 중요하다.',
   'Worm', 1, @mock_exam_id, 96, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '네트워크 접속 장치(MAC) 주소를 IP 주소로 변환하는 프로토콜은 무엇인가?\n\n① ICMP\n② ARP\n③ RARP\n④ IP', 'MCQ', 3, '정답: 3. RARP는 MAC 주소를 IP 주소로 변환하는 프로토콜이다.\n\n**오답 풀이**\n- 1번: ICMP는 오류 메시지와 제어 메시지 전달에 사용된다.\n- 2번: ARP는 IP 주소를 MAC 주소로 변환한다.\n- 3번: RARP가 MAC 주소를 IP 주소로 변환한다.\n- 4번: IP는 패킷 전달 프로토콜이다.\n\n**보충 개념**\nARP와 RARP는 주소 해석 방향이 서로 반대이다.',
   'RARP', 1, @mock_exam_id, 97, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '데이터를 암호화하여 전달하는 방식의 원격 제어 서비스는 무엇인가?\n\n① SSH\n② telnet\n③ POP3\n④ HTTPS', 'MCQ', 1, '정답: 1. SSH는 원격 접속 데이터를 암호화하여 안전하게 전달하는 서비스이다.\n\n**오답 풀이**\n- 1번: SSH가 암호화 원격 접속 서비스이다.\n- 2번: telnet은 암호화되지 않은 원격 접속 방식이다.\n- 3번: POP3는 이메일 수신 프로토콜이다.\n- 4번: HTTPS는 웹 통신 보안 프로토콜이다.\n\n**보충 개념**\nSSH는 원격 로그인, 명령 실행, 파일 전송 등에 안전하게 사용된다.',
   'SSH', 1, @mock_exam_id, 98, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '웹 서비스에 사용되는 프로토콜 중, 전체 통신 내용을 암호화하며 443번 포트를 사용하는 프로토콜은 무엇인가?\n\n① HTTP\n② S-HTTP\n③ HSTP\n④ HTTPS', 'MCQ', 4, '정답: 4. HTTPS는 HTTP에 SSL/TLS를 적용하여 전체 통신을 암호화하며 기본적으로 443번 포트를 사용한다.\n\n**오답 풀이**\n- 1번: HTTP는 기본적으로 80번 포트를 사용하며 암호화되지 않는다.\n- 2번: S-HTTP는 일부 페이지 보안과 관련된다.\n- 3번: HSTP는 일반적인 웹 보안 프로토콜 명칭이 아니다.\n- 4번: HTTPS가 정답이다.\n\n**보충 개념**\nHTTPS는 서버 인증, 통신 암호화, 데이터 무결성 보호를 제공한다.',
   'HTTPS', 1, @mock_exam_id, 99, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중 데이터 링크 계층에 해당하는 네트워크 장비는 무엇인가?\n\n① 스위치\n② 전송 회선\n③ 리피터\n④ 허브', 'MCQ', 1, '정답: 1. 스위치는 MAC 주소를 기반으로 프레임을 전달하는 데이터 링크 계층 장비이다.\n\n**오답 풀이**\n- 1번: 스위치는 데이터 링크 계층 장비이다.\n- 2번: 전송 회선은 물리 계층 요소이다.\n- 3번: 리피터는 물리 계층 장비이다.\n- 4번: 허브는 물리 계층 장비이다.\n\n**보충 개념**\n데이터 링크 계층은 프레임 전달과 MAC 주소 기반 통신을 담당한다.',
   '스위치', 1, @mock_exam_id, 100, 'NONE', NULL, NOW(6), NOW(6))
;